# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.UI;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;

    public Text healthText;
    public Text currencyText;
}

[System.Serializable]
public class Item
{
    public string name;
    public int price;
    public HealthPotion potion; // Example of an item that affects player's health
}

[System.Serializable]
public class HealthPotion
{
    public int healAmount = 50;
}

public class DamageCalculator : MonoBehaviour
{
    public PlayerStats player;
    public float damagePerHit = 10f;

    void Update()
    {
        if (Input.GetMouseButtonDown(0))
        {
            DealDamage();
        }
    }

    void DealDamage()
    {
        player.health -= Mathf.RoundToInt(damagePerHit);
        UpdateUI();
    }

    void UpdateUI()
    {
        player.healthText.text = "Health: " + player.health;
        player.currencyText.text = "Currency: " + player.currency;
    }
}

public class Shop : MonoBehaviour
{
    public List<Item> itemsForSale = new List<Item>();

    void OnGUI()
    {
        for (int i = 0; i < itemsForSale.Count; i++)
        {
            if (GUI.Button(new Rect(10, 50 + i * 50, 200, 50), itemsForSale[i].name))
            {
                BuyItem(itemsForSale[i]);
            }
        }
    }

    void BuyItem(Item item)
    {
        if (player.currency >= item.price)
        {
            player.currency -= item.price;
            player.currencyText.text = "Currency: " + player.currency;

            switch (item)
            {
                case HealthPotion potion:
                    player.health += potion.healAmount;
                    if (player.health > 100) player.health = 100;
                    player.healthText.text = "Health: " + player.health;
                    break;
            }
        }
    }
}